                       : done
                       ? token.colorSuccess
                       : token.colorFillSecondary,
                     color:
                       active || done ? '#fff' : token.colorTextSecondary
                   }}
                 >
                   {done ? <CheckOutlined /> : idx + 1}
                 </div>
                 <span>{s.label}</span>
               </div>
             );
           })}
         </div>

         <div
           style={{
             flex: 1,
             padding: '24px 28px',
             minWidth: 0,
             overflow: 'auto',
             maxHeight: 560
           }}
         >
           <StepHeader index={step + 1} title={stepTitle(step)} />

           {step === 0 && (
             <RelationshipStep
               cardinality={cardinality}
               setCardinality={setCardinality}
               joinMethod={joinMethod}
               setJoinMethod={setJoinMethod}
             />
           )}

           {step === 1 && (
             <ResourcesStep
               objects={objects}
               source={source}
               target={target}
               sourceApi={sourceApi}
               targetApi={targetApi}
               setSourceApi={(v) => {
                 setSourceApi(v);
                 setFkProp(undefined);
+                setTargetFkProp(undefined);
               }}
               setTargetApi={setTargetApi}
               onSwap={swapEnds}
               joinMethod={joinMethod}
               fkProp={fkProp}
               setFkProp={setFkProp}
+              targetFkProp={targetFkProp}
+              setTargetFkProp={setTargetFkProp}
               joinTableRef={joinTableRef}
               setJoinTableRef={setJoinTableRef}
               backingObj={backingObj}
               setBackingObj={setBackingObj}
+              existingPairs={existingPairs}
+              pairExists={pairExists}
