             value={apiName}
             onChange={(e) => setApiName(e.target.value)}
             placeholder={`${source.api_name}_to_${target.api_name}`}
             style={{ fontFamily: 'monospace', maxWidth: 520 }}
           />
         </Form.Item>
       </Form>

       <div
         style={{
           display: 'grid',
           gridTemplateColumns: '1fr 1fr',
           gap: 16,
           marginTop: 4
         }}
       >
