           side="forward"
           heading={`每个 ${srcLabel} ${syn.forward.replace('B', tgtLabel)}`}
           nameLabel="显示名"
           nameValue={displayName}
           onNameChange={setDisplayName}
           apiLabel="API 名称（正向）"
           apiValue={apiName}
