         />
         <NameBlock
           side="reverse"
           heading={`每个 ${tgtLabel} ${syn.reverse.replace('A', srcLabel)}`}
           nameLabel="反向显示名"
           nameValue={reverseDisplayName}
           onNameChange={setReverseDisplayName}
           apiLabel="API 名称（反向）"
           apiValue={suggestReverseApiName(apiName)}
           apiReadonly
           hint="从目标对象视角看到的关系名；留空则导出 null"
         />
       </div>

       <div style={{ marginTop: 16 }}>
         <div
           style={{
             fontSize: 12,
             color: token.colorTextSecondary,
             marginBottom: 4
