           onChange={(e) => setDescription(e.target.value)}
           placeholder="对该关系的说明（可选）"
         />
       </div>
     </div>
   );
 }

 function NameBlock({
   side,
   heading,
   nameLabel,
   nameValue,
   onNameChange,
   apiLabel,
   apiValue,
   apiReadonly,
   hint,
   required
 }: {
   side: 'forward' | 'reverse';
   heading: string;
   nameLabel: string;
   nameValue: string;
   onNameChange: (v: string) => void;
   apiLabel: string;
   apiValue: string;
   apiReadonly?: boolean;
   hint?: string;
   required?: boolean;
 }) {
   const { token } = theme.useToken();
   return (
     <div
       style={{
         border: `1px solid ${token.colorBorderSecondary}`,
         borderRadius: 6,
         padding: 12
       }}
     >
       <div
         style={{
           fontSize: 11,
           fontWeight: 600,
           color: token.colorTextTertiary,
           textTransform: 'uppercase',
           marginBottom: 4,
           letterSpacing: 0.5
         }}
       >
         {side === 'forward' ? '正向' : '反向'}
       </div>
       <div
         style={{
           fontSize: 13,
           color: token.colorText,
           marginBottom: 10,
           minHeight: 36
         }}
       >
         {heading}
       </div>
       <div style={{ marginBottom: 8 }}>
         <Typography.Text
           type="secondary"
           style={{ fontSize: 11, display: 'block', marginBottom: 2 }}
         >
           {nameLabel}
           {required && <span style={{ color: '#ff4d4f', marginLeft: 2 }}>*</span>}
         </Typography.Text>
         <Input
           size="small"
           value={nameValue}
           onChange={(e) => onNameChange(e.target.value)}
           placeholder={side === 'reverse' ? '可选' : ''}
         />
       </div>
       <div>
         <Typography.Text
           type="secondary"
           style={{ fontSize: 11, display: 'block', marginBottom: 2 }}
         >
           {apiLabel}
         </Typography.Text>
         <Input
           size="small"
           value={apiValue}
           disabled={apiReadonly}
           style={{ fontFamily: 'monospace' }}
         />
       </div>
       {hint && (
         <div
           style={{
             fontSize: 11,
             color: token.colorTextTertiary,
             marginTop: 6,
             lineHeight: 1.4
           }}
         >
           {hint}
         </div>
       )}
     </div>
   );
 }

 function syntaxForCardinality(c: Cardinality) {
   switch (c) {
     case 'one_to_one':
       return { forward: '关联一个 B', reverse: '关联一个 A' };
     case 'one_to_many':
       return { forward: '关联多个 B', reverse: '关联一个 A' };
     case 'many_to_one':
       return { forward: '关联一个 B', reverse: '关联多个 A' };
     case 'many_to_many':
       return { forward: '关联多个 B', reverse: '关联多个 A' };
   }
 }

