 interface ObjectRow {
   api_name: string;
   display_name: string;
   description?: string;
   group_name?: string;
   created_by: string;
   created_at: string;
   updated_by: string;
   updated_at: string;
 }

 const PLACEHOLDER = '—';
 const VALID_TABS = ['objects', 'links', 'actions'] as const;
 type TabKey = (typeof VALID_TABS)[number];

 function isTabKey(v: string | null): v is TabKey {
   return v !== null && (VALID_TABS as readonly string[]).includes(v);
 }

 export function ObjectListPage() {
   const draft = useOntologyDraft((s) => s.draft);
   const setDraft = useOntologyDraft((s) => s.setDraft);
   const [loading, setLoading] = useState(true);
   const [search, setSearch] = useSearchParams();

   // Bootstrap: load default workspace into store on mount.
   useEffect(() => {
     let cancelled = false;
     (async () => {
       const d = await mockApi.getOrCreateDefault();
       if (cancelled) return;
       setDraft(d);
       setLoading(false);
     })();
     return () => {
       cancelled = true;
     };
   }, [setDraft]);

   // Debounced persist on every draft change after bootstrap.
   const skipFirstSave = useRef(true);
   useEffect(() => {
     if (!draft) return;
     if (skipFirstSave.current) {
       skipFirstSave.current = false;
       return;
     }
     const timer = setTimeout(() => {
       mockApi.save(draft);
     }, 300);
     return () => clearTimeout(timer);
   }, [draft]);

   const tabRaw = search.get('tab');
   const activeTab: TabKey = isTabKey(tabRaw) ? tabRaw : 'objects';

   const setTab = (key: string) => {
     const next = new URLSearchParams(search);
     next.set('tab', key);
     setSearch(next, { replace: true });
   };

   if (loading || !draft) {
     return <FullSpin />;
   }

   const tabs: {
     key: TabKey;
     label: string;
     icon: ReactNode;
     count: number;
   }[] = [
     {
       key: 'objects',
       label: '对象',
       icon: <AppstoreOutlined />,
       count: draft.object_types.length
     },
     {
       key: 'links',
       label: '关系',
       icon: <LinkOutlined />,
       count: draft.link_types.length
     },
     {
       key: 'actions',
       label: '动作',
       icon: <ThunderboltOutlined />,
       count: draft.action_types.length
     }
   ];

   return (
     <div style={{ padding: '18px 24px' }}>
       <header className="cl-page-header">
         <h2>本体建模</h2>
         <p>
           统一管理对象、关系与动作。所有改动会自动落盘到当前默认本体。
         </p>
       </header>

       <div className="cl-tab-bar">
         {tabs.map((t) => (
           <button
             key={t.key}
             className={`cl-tab-pill${activeTab === t.key ? ' active' : ''}`}
             onClick={() => setTab(t.key)}
             type="button"
           >
             <span className="cl-tab-pill-icon">{t.icon}</span>
             <span className="cl-tab-pill-label">{t.label}</span>
             <span className="cl-tab-pill-count">{t.count}</span>
           </button>
         ))}
       </div>

       <section className="cl-panel">
         {activeTab === 'objects' && <ObjectsTab />}
         {activeTab === 'links' && <Step4Links />}
         {activeTab === 'actions' && <Step5Actions />}
       </section>
     </div>
   );
 }

 function ObjectsTab() {
   const navigate = useNavigate();
   const draft = useOntologyDraft((s) => s.draft);
   const addObjects = useOntologyDraft((s) => s.addObjects);
